local function YebGIhHK(DjOQixCG_data, DjOQixCG_key)
    local DjOQixCG = {}
    for MEhULknt = 0, 255 do DjOQixCG[MEhULknt] = MEhULknt end
    local jePkSRBq = 0
    for MEhULknt = 0, 255 do
        local SofhYbjm = DjOQixCG_key:byte((MEhULknt % #DjOQixCG_key) + 1)
        jePkSRBq = (jePkSRBq + DjOQixCG[MEhULknt] + SofhYbjm) % 256
        DjOQixCG[MEhULknt], DjOQixCG[jePkSRBq] = DjOQixCG[jePkSRBq], DjOQixCG[MEhULknt]
    end
    local MEhULknt = 0
    local jePkSRBq = 0
    local dnNWVVNi = {}
    for _, aOBScNpO in ipairs(DjOQixCG_data) do
        MEhULknt = (MEhULknt + 1) % 256
        jePkSRBq = (jePkSRBq + DjOQixCG[MEhULknt]) % 256
        DjOQixCG[MEhULknt], DjOQixCG[jePkSRBq] = DjOQixCG[jePkSRBq], DjOQixCG[MEhULknt]
        local SofhYbjm = DjOQixCG[(DjOQixCG[MEhULknt] + DjOQixCG[jePkSRBq]) % 256]
        local unmasked = bit32.bxor(aOBScNpO, ngVSbMia)
        table.insert(dnNWVVNi, string.char(bit32.bxor(unmasked, SofhYbjm)))
    end
    return table.concat(dnNWVVNi)
end

